var nodes=[{name:rawData.effect,x:600,y:200}];
var links=[];
rawData.bones.forEach(function(b,i){
  var y=i<2?100+i*60:260+((i-2)*60);
  nodes.push({name:b.cat,x:400-i*50,y:y});
  links.push({source:b.cat,target:rawData.effect});
  b.causes.forEach(function(c,j){
    var cn=b.cat+'-'+c;
    nodes.push({name:c,x:250-i*50,y:y-20+j*40});
    links.push({source:c,target:b.cat});
  });
});
transformedData={nodes:nodes,links:links};
